    pay_amt_sum BIGINT DEFAULT 0 COMMENT '当日收入（运营口径，分）',
    retain_d1_cnt BIGINT DEFAULT 0 COMMENT 'D1活跃留存数',
    retain_d3_cnt BIGINT DEFAULT 0 COMMENT 'D3活跃留存数',
    retain_d7_cnt BIGINT DEFAULT 0 COMMENT 'D7活跃留存数（次周留存，买量核心）',
    retain_d14_cnt BIGINT DEFAULT 0 COMMENT 'D14活跃留存数',
    retain_d30_cnt BIGINT DEFAULT 0 COMMENT 'D30活跃留存数（次月留存）',
    retain_d90_cnt BIGINT DEFAULT 0 COMMENT 'D90活跃留存数',
    ltv_1d BIGINT DEFAULT 0 COMMENT '新用户LTV D1（D0当天累计充值，分）',
    ltv_3d BIGINT DEFAULT 0 COMMENT '新用户LTV D3（分）',
    ltv_7d BIGINT DEFAULT 0 COMMENT '新用户LTV D7（分，买量核心效果指标）',
    ltv_14d BIGINT DEFAULT 0 COMMENT '新用户LTV D14（分）',
    ltv_30d BIGINT DEFAULT 0 COMMENT '新用户LTV D30（分，ROI核心分母）',
    ltv_60d BIGINT DEFAULT 0 COMMENT '新用户LTV D60（分）',
    ltv_90d BIGINT DEFAULT 0 COMMENT '新用户LTV D90（分）',
    ltv_180d BIGINT DEFAULT 0 COMMENT '新用户LTV D180（分）',
    ltv_360d BIGINT DEFAULT 0 COMMENT '新用户LTV D360（分，品质游戏长周期ROI）',
    max_ltv_day_filled SMALLINT DEFAULT 0 COMMENT '已回填最大LTV天数（0/1/3/7/14/30/60/90/180/360）',
    is_spend_synced TINYINT DEFAULT 0 COMMENT '广告消耗是否已同步（0=未同步 1=已同步）',
    last_update_ts BIGINT DEFAULT 0 COMMENT '最后更新时间戳（ms）',
    KEY `idx_ads_buy_channel_roi_daily_1` (`stat_date`, `papp_id`, `app_id`, `cch_id`, `bus_company_id`, `ptid`),
