) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='【ADS买量ROI日报】广告渠道层级|消耗+新增+留存+LTV D1~D360|Golang T+N回填|roi_360d=ltv_360d/100/spend';


