-- Source: ads/ads_op_game_overview_daily.sql (dw_ads.ads_op_game_overview_daily)
DROP TABLE IF EXISTS `ads_op_game_overview_daily`;
CREATE TABLE `ads_op_game_overview_daily` (
    stat_date DATE NOT NULL COMMENT '统计日期',
    papp_id INT NOT NULL DEFAULT 0 COMMENT '应用维度（运营视角，不拆解广告层级）',
    app_id INT NOT NULL DEFAULT 100000,
    cch_id INT NOT NULL DEFAULT 100,
    bus_company_id VARCHAR(128) NOT NULL DEFAULT 't1',
    dau BIGINT COMMENT '日活跃用户数',
    dar BIGINT COMMENT '日活跃角色数',
    login_cnt BIGINT COMMENT '登录总次数',
    platform_new_user_cnt BIGINT COMMENT '平台新用户数（enter_date=reg_date，买量口径）',
    game_new_user_cnt BIGINT COMMENT '游戏新用户数（login_type=2，运营口径）',
    ad_new_user_cnt BIGINT COMMENT '广告来源新用户（ad_pmedia不为空）',
    organic_new_user_cnt BIGINT COMMENT '自然量新用户（ad_pmedia为空）',
    new_role_cnt BIGINT COMMENT '新建角色数（is_new_role=1）',
    retain_d1_cnt BIGINT COMMENT '次日留存数（D+1）',
    retain_d3_cnt BIGINT DEFAULT 0,
    retain_d7_cnt BIGINT COMMENT '7日留存数（次周留存）',
    retain_d14_cnt BIGINT DEFAULT 0,
    retain_d30_cnt BIGINT COMMENT '30日留存数（次月留存）',
    pay_user_cnt BIGINT COMMENT '付费用户数',
    first_pay_user_cnt BIGINT COMMENT '首次付费用户数（T+1 Golang回填）',
    pay_amt_sum BIGINT COMMENT '收入合计（运营口径，分）',
    statistical_pay_amt_sum BIGINT COMMENT '收入合计（财务口径，分）',
    refund_amt_sum BIGINT COMMENT '退款金额（分）',
    ltv_7d BIGINT COMMENT '7日LTV（新用户7天累计收入，分）',
    ltv_30d BIGINT COMMENT '30日LTV（分）',
    max_retain_day_filled SMALLINT COMMENT '已回填最大留存天数',
    is_finalized TINYINT COMMENT '0=T+0近实时 1=T+1已最终确认',
    last_update_ts BIGINT COMMENT '最后更新时间戳(ms)',
    KEY `idx_ads_op_game_overview_daily_1` (`stat_date`, `papp_id`, `app_id`, `cch_id`, `bus_company_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='【ADS】运营游戏日报 | 不拆广告维度 | arpu=pay_amt_sum/100/dau | 留存率=retain_dN/game_new_user_cnt | 金额分单位';


-- Source: dws/v4/dws_v4_ad_cost_daily.sql (dw_dws.dws_v4_ad_cost_daily)
DROP TABLE IF EXISTS `dws_v4_ad_cost_daily`;
CREATE TABLE `dws_v4_ad_cost_daily` (
    stat_date DATE NOT NULL COMMENT '统计日期（广告花费发生日，分区键）',
    papp_id INT NOT NULL DEFAULT 0 COMMENT '主游戏ID（0=平台级花费）',
    app_id INT NOT NULL DEFAULT 100000 COMMENT '子游戏ID',
    cch_id INT NOT NULL DEFAULT 100 COMMENT '渠道商ID',
    md_traceid VARCHAR(200) NOT NULL DEFAULT '' COMMENT '广告追踪码（买量链路唯一标识，与cohort_user关联键）',
    ad_pmedia VARCHAR(128) NOT NULL DEFAULT '' COMMENT '广告平台标识（bytedance/tencent/meta/google等）',
    ad_cch_id BIGINT NOT NULL DEFAULT 0 COMMENT '广告渠道ID（对应 dim_ad_attribute_profile.ad_cch_id）',
    ad_account_id VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告账号ID（平台投放账号）',
    tg_level_1 VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告层级1（推广计划 Campaign ID/Name）',
    tg_level_2 VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告层级2（广告组 AdGroup ID/Name）',
    tg_level_3 VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告层级3（广告创意 Ad ID/Name）',
    ad_material_id VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告素材ID（有时广告平台不返回，可为空）',
    ad_position VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告版位（开屏/信息流/激励视频等）',
    currency VARCHAR(128) NOT NULL DEFAULT 'CNY' COMMENT '花费货币（CNY/USD等）',
    cost_amt BIGINT COMMENT '广告花费金额（分，与收入 pay_amt 同单位；/100 转元）',
    impression_cnt BIGINT COMMENT '曝光次数（来自广告平台上报）',
    click_cnt BIGINT COMMENT '点击次数',
    platform_convert_cnt BIGINT COMMENT '平台上报转化数（激活/注册/付费依平台口径，用于 CPA 分析）',
    is_finalized TINYINT COMMENT '0=临时值(T+0估算) 1=T+1精确回填 2=T+3最终结算值（部分平台数据延迟）',
    sync_ts BIGINT COMMENT '最近一次 API 同步时间戳（毫秒）',
    KEY `idx_dws_v4_ad_cost_daily_1` (`stat_date`, `papp_id`, `app_id`, `cch_id`, `md_traceid`(191), `ad_pmedia`),
    KEY `idx_dws_v4_ad_cost_daily_2` (`ad_cch_id`, `ad_account_id`, `tg_level_1`, `tg_level_2`, `tg_level_3`, `ad_material_id`),
    KEY `idx_dws_v4_ad_cost_daily_3` (`ad_position`, `currency`)
