-- Source: dws/v4/dws_v4_cohort_device.sql (dw_dws.dws_v4_cohort_device)
DROP TABLE IF EXISTS `dws_v4_cohort_device`;
CREATE TABLE `dws_v4_cohort_device` (
    enter_date DATE NOT NULL COMMENT '设备进入日期（队列起点，device_enter_date，按月分区键）',
    enter_hour TINYINT NOT NULL DEFAULT 0 COMMENT '设备进入小时（0~23，来自 dwd_attr_device_enter.enter_at）',
    papp_id INT NOT NULL DEFAULT 0 COMMENT '主游戏ID',
    app_id INT NOT NULL DEFAULT 100000 COMMENT '子游戏ID',
    cch_id INT NOT NULL DEFAULT 100 COMMENT '渠道商ID',
    app_type TINYINT NOT NULL DEFAULT 1 COMMENT '游戏类型：1手游 2H5 3小游戏',
    md_traceid VARCHAR(200) NOT NULL DEFAULT '' COMMENT '广告追踪码（设备入场时归因，广告平台口径）',
    ad_cch_id BIGINT NOT NULL DEFAULT 0 COMMENT '广告渠道ID（0=无归因/自然量）',
    ad_account_id VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告账号ID',
    tg_level_1 VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告层级1（推广计划）',
    tg_level_2 VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告层级2（广告组）',
    tg_level_3 VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告层级3（广告创意）',
    ad_material_id VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告素材ID',
    ad_position VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告版位',
    day_n SMALLINT NOT NULL DEFAULT 0 COMMENT '入场后第N天（0=D0入场当天，1~360=后续留存追踪天数）',
    d0_enter_device_cnt BIGINT COMMENT 'D0进入设备数（该队列设备基数，留存率分母）',
    d0_pay_device_cnt BIGINT COMMENT 'D0付费设备数（付费留存率分母）',
    d0_pay_amt BIGINT COMMENT 'D0充值金额（分，首日ROI参考）',
    d0_enter_device_bitmap LONGBLOB COMMENT 'D0进入设备精确Bitmap（BITMAP_HASH(device_id)）',
    d0_pay_device_bitmap LONGBLOB COMMENT 'D0付费设备精确Bitmap（付费留存计算基准）',
    retain_device_cnt BIGINT COMMENT '第N天留存设备数（D0队列在第N天活跃的设备数）',
    retain_device_bitmap LONGBLOB COMMENT '第N天留存设备精确Bitmap（BITMAP_HASH(device_id)）',
    pay_retain_device_cnt BIGINT COMMENT 'D0付费设备在第N天的留存数（付费设备留存率=pay_retain/d0_pay_device_cnt）',
    pay_retain_device_bitmap LONGBLOB COMMENT 'D0付费设备中第N天仍留存的精确Bitmap',
    day_n_pay_amt BIGINT COMMENT '第N天充值金额（分，该队列在第N天的付款增量）',
    day_n_pay_device_cnt BIGINT COMMENT '第N天付费设备数',
    day_n_pay_order_cnt BIGINT COMMENT '第N天付费订单数',
    day_n_pay_device_bitmap LONGBLOB COMMENT '第N天付费设备精确Bitmap（用于跨天去重累计）',
    uid_cnt_on_device BIGINT COMMENT '第N天设备上付费的不同uid数（刷量检测：>1.5=多账号风险，配合day_n_pay_device_cnt使用）',
    cum_pay_amt BIGINT COMMENT '累计充值金额前缀和（D0~DN，分；设备视角LTV基础数据）',
    cum_pay_order_cnt BIGINT COMMENT '累计付费订单数前缀和（D0~DN）',
    cum_pay_device_cnt BIGINT COMMENT '累计付款设备数（精确跨天去重，来自BITMAP_COUNT(cum_pay_device_bitmap)）',
    cum_pay_device_bitmap LONGBLOB COMMENT '累计付款设备精确Bitmap（D0~DN BITMAP_OR，跨天精确去重）',
    is_filled TINYINT COMMENT '0=待回填 1=Golang已精确回填（REPLACE幂等，重跑安全）',
    KEY `idx_dws_v4_cohort_device_1` (`enter_date`, `enter_hour`, `papp_id`, `app_id`, `cch_id`, `app_type`),
    KEY `idx_dws_v4_cohort_device_2` (`md_traceid`(191), `ad_cch_id`, `ad_account_id`, `tg_level_1`, `tg_level_2`, `tg_level_3`),
    KEY `idx_dws_v4_cohort_device_3` (`ad_material_id`, `ad_position`, `day_n`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='【DWS v4 设备队列】设备归因视角 | D0-D360留存+LTV前缀和+跨天去重+刷量检测 | 替代dws_device_cohort_stat+dws_device_enter_ltv_daily+dws_device_retention_cohort | Golang T+N逐日回填';


