    tg_level_3 VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告层级3（广告创意）',
    ad_material_id VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告素材ID',
    ad_position VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告版位',
    day_n SMALLINT NOT NULL DEFAULT 0 COMMENT '入场后第N天（0=D0入场当天，1~360=后续留存追踪天数）',
    d0_enter_user_cnt BIGINT COMMENT 'D0进入用户数（留存率分母，该队列的入场规模）',
    d0_reg_user_cnt BIGINT COMMENT 'D0注册用户数（is_platform_new_user=1 AND login_type=2，买量ROI分母）',
    d0_pay_user_cnt BIGINT COMMENT 'D0付费用户数（付费留存率分母）',
    d0_pay_amt BIGINT COMMENT 'D0充值金额（分，首日ROI参考）',
    d0_enter_user_bitmap LONGBLOB COMMENT 'D0进入用户精确Bitmap（TO_BITMAP(uid)）',
    d0_pay_user_bitmap LONGBLOB COMMENT 'D0付费用户精确Bitmap（付费留存计算基准）',
    retain_user_cnt BIGINT COMMENT '第N天留存用户数（D0队列在第N天活跃数）',
    retain_user_bitmap LONGBLOB COMMENT '第N天留存用户精确Bitmap（TO_BITMAP(uid)）',
    pay_retain_user_cnt BIGINT COMMENT 'D0付费用户在第N天的留存数（付费留存率=pay_retain/d0_pay_user_cnt）',
    pay_retain_user_bitmap LONGBLOB COMMENT 'D0付费用户中第N天仍留存的精确Bitmap',
    day_n_pay_amt BIGINT COMMENT '第N天充值金额（分，队列在第N天的付款增量）',
    day_n_pay_user_cnt BIGINT COMMENT '第N天充值用户数',
    day_n_pay_order_cnt BIGINT COMMENT '第N天付费订单数',
    day_n_pay_user_bitmap LONGBLOB COMMENT '第N天付费用户精确Bitmap（用于跨天去重累计）',
    cum_pay_amt BIGINT COMMENT '累计充值金额前缀和（D0~DN，分；人均LTV=cum_pay_amt/d0_enter_user_cnt）',
    cum_pay_order_cnt BIGINT COMMENT '累计付费订单数前缀和（D0~DN）',
    cum_pay_user_cnt BIGINT COMMENT '累计付款用户数（精确跨天去重，来自BITMAP_COUNT(cum_pay_user_bitmap)）',
    cum_pay_user_bitmap LONGBLOB COMMENT '累计付款用户精确Bitmap（D0~DN BITMAP_OR，跨天精确去重核心）',
    is_filled TINYINT COMMENT '0=待回填 1=Golang已精确回填（REPLACE幂等，重跑安全）',
    KEY `idx_dws_v4_cohort_user_1` (`enter_date`, `enter_hour`, `papp_id`, `app_id`, `cch_id`, `app_type`),
    KEY `idx_dws_v4_cohort_user_2` (`md_traceid`(191), `ad_cch_id`, `ad_account_id`, `tg_level_1`, `tg_level_2`, `tg_level_3`),
    KEY `idx_dws_v4_cohort_user_3` (`ad_material_id`, `ad_position`, `day_n`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='【DWS v4 用户队列】用户归因视角 | D0-D360留存+付费留存+LTV前缀和+跨天去重 | 替代dws_user_cohort_stat+dws_user_enter_ltv_daily | Golang T+N逐日回填';


