    md_traceid VARCHAR(200) NOT NULL DEFAULT '' COMMENT '广告追踪码（设备激活时归因）',
    ad_cch_id BIGINT NOT NULL DEFAULT 0 COMMENT '广告渠道ID（0=无归因/自然量）',
    ad_account_id VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告账号ID',
    tg_level_1 VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告层级1（推广计划）',
    tg_level_2 VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告层级2（广告组）',
