    KEY `idx_dws_v4_device_daily_2` (`md_traceid`(191), `ad_cch_id`, `ad_account_id`, `tg_level_1`, `tg_level_2`, `tg_level_3`),
    KEY `idx_dws_v4_device_daily_3` (`ad_material_id`, `ad_position`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='【DWS v4 设备日流量】设备归因视角 | 激活+买量/自然量拆分 | 小时级 | 替代 dws_device_activate_daily/dws_ad_material_hourly | MV近实时+T+1精确BITMAP';


