    stat_hour TINYINT NOT NULL DEFAULT 0 COMMENT '统计小时（0~23）',
    papp_id INT NOT NULL DEFAULT 0 COMMENT '主游戏ID',
    app_id INT NOT NULL DEFAULT 100000 COMMENT '子游戏ID',
    cch_id INT NOT NULL DEFAULT 100 COMMENT '渠道商ID',
    app_type TINYINT NOT NULL DEFAULT 1 COMMENT '游戏类型：1手游 2H5 3小游戏',
    md_traceid VARCHAR(200) NOT NULL DEFAULT '' COMMENT '广告追踪码（买量链路唯一标识）',
    ad_cch_id BIGINT NOT NULL DEFAULT 0 COMMENT '广告渠道ID（0=无归因/自然量）',
    ad_account_id VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告账号ID',
    tg_level_1 VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告层级1（推广计划）',
    tg_level_2 VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告层级2（广告组）',
    tg_level_3 VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告层级3（广告创意）',
    ad_material_id VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告素材ID',
    ad_position VARCHAR(100) NOT NULL DEFAULT '' COMMENT '广告版位',
    login_user_cnt BIGINT COMMENT '当日登录用户数（DAU，COUNT DISTINCT uid）',
    login_device_cnt BIGINT COMMENT '当日登录设备数（COUNT DISTINCT device_id）',
    login_user_bitmap LONGBLOB COMMENT '登录用户精确Bitmap（TO_BITMAP(uid)，Golang T+1）',
    new_enter_user_cnt BIGINT COMMENT '新增进入用户数（login_type=2，买量核心漏斗指标）',
    new_enter_device_cnt BIGINT COMMENT '新增进入设备数',
    new_enter_user_bitmap LONGBLOB COMMENT '新增进入用户精确Bitmap（TO_BITMAP(uid)）',
    reg_user_cnt BIGINT COMMENT '注册用户数（平台新用户首次进入，买量ROI核心口径）',
    reg_device_cnt BIGINT COMMENT '注册设备数',
    reg_user_bitmap LONGBLOB COMMENT '注册用户精确Bitmap（TO_BITMAP(uid)）',
    new_role_cnt BIGINT COMMENT '新建角色数（is_new_role=1）',
    new_enter_role_cnt BIGINT COMMENT '新增进入用户新建角色数（创角转化漏斗节点）',
    trans_amt BIGINT COMMENT '当日充值金额（分，运营口径）',
    pay_user_cnt BIGINT COMMENT '当日付费用户数',
    pay_order_cnt BIGINT COMMENT '当日付费订单数',
    pay_user_bitmap LONGBLOB COMMENT '当日付费用户精确Bitmap（TO_BITMAP(uid)）',
    first_pay_amt BIGINT COMMENT '首次付费金额（分，is_first_pay=1；ROI分子）',
    first_pay_user_cnt BIGINT COMMENT '首次付费用户数（转化率=first_pay/reg）',
    first_pay_user_bitmap LONGBLOB COMMENT '首次付费用户精确Bitmap（TO_BITMAP(uid)）',
    is_finalized TINYINT COMMENT '0=MV近似(order_at日期) 1=Golang T+1精确(pay_at日期+LONGBLOB+精确first_pay)',
    KEY `idx_dws_v4_user_daily_1` (`stat_date`, `stat_hour`, `papp_id`, `app_id`, `cch_id`, `app_type`),
    KEY `idx_dws_v4_user_daily_2` (`md_traceid`(191), `ad_cch_id`, `ad_account_id`, `tg_level_1`, `tg_level_2`, `tg_level_3`),
    KEY `idx_dws_v4_user_daily_3` (`ad_material_id`, `ad_position`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='【DWS v4 用户日流量】用户归因视角 | 登录+角色+付费 | 小时级 | 替代 dws_app_daily_active/dws_revenue_daily/dws_ad_material_hourly | MV近实时+T+1精确BITMAP';


-- Source: dws/v4/dws_v4_user_segment.sql (dw_dws.dws_v4_user_segment)
DROP TABLE IF EXISTS `dws_v4_user_segment`;
CREATE TABLE `dws_v4_user_segment` (
    enter_date DATE NOT NULL COMMENT '入场日期（队列起点，分区键）',
    papp_id INT NOT NULL DEFAULT 0 COMMENT '主游戏ID',
    app_id INT NOT NULL DEFAULT 100000 COMMENT '子游戏ID',
    cch_id INT NOT NULL DEFAULT 100 COMMENT '渠道商ID',
    segment_key VARCHAR(100) NOT NULL DEFAULT '' COMMENT '分群标签（命名规范：{行为主体}_{条件}_{阈值}[_{时间窗口}]）',
    user_bitmap LONGBLOB COMMENT '符合分群条件的uid精确Bitmap（TO_BITMAP(uid)）',
    user_cnt BIGINT COMMENT '分群用户数（BITMAP_COUNT(user_bitmap)，冗余存储加速查询）',
    computed_ts BIGINT COMMENT '分群计算完成的时间戳（毫秒，排查数据延迟）',
    KEY `idx_dws_v4_user_segment_1` (`enter_date`, `papp_id`, `app_id`, `cch_id`, `segment_key`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='【DWS v4 用户分群】Bitmap分群 | 与cohort_user做BITMAP_AND实现任意条件留存/LTV过滤 | 替代v3 dws_v3_user_segment';

SET FOREIGN_KEY_CHECKS=1;
